-- map of verbose project names to canonical ones local projectMap = { commons = 'c', commonscat = 'c', ["wikimedia commons"] = 'c', meta = 'm', metawiki = 'm', ["meta-wiki"] = 'm', wikibooks = 'b', wbk = 'b', wb = 'b', cookbook = 'b', wikijunior = 'b', wikidata = 'd', data = 'd', wikiquote = 'q', quote = 'q', wqt = 'q', wikipedia = 'iw', wp = 'iw', w = 'iw', iw1 = 'iw', iw2 = 'iw', wikisource = 's', source = 's', ws = 's', wikisource2 = 's', source2 = 's', ws2 = 's', s2 = 's', wiktionary = 'wikt', wkt = 'wikt', wdy = 'wikt', wikinews = 'n', news = 'n', wnw = 'n', wikispecies = 'species', wikiversity='v', wvy='v', wikivoyage = 'voy', voyage = 'voy', mediawiki = 'mw', outreachwiki = 'outreach', wikifunctions = 'f' }
-- logos per project local logo = { c = "Commons-logo.svg", m = 'Wikimedia Community Logo.svg', b = 'Wikibooks-logo.svg', d = 'Wikidata-logo.svg', q = 'Wikiquote-logo.svg', iw = 'Wikipedia-logo-v2.svg', s = 'Wikisource-logo.svg', wikt = 'Wiktionary-logo-en-v2.svg', n = 'Wikinews-logo.svg', species = 'Wikispecies-logo.svg', v = 'Wikiversity logo 2017.svg', voy = 'Wikivoyage-Logo-v3-icon.svg', mw = 'MediaWiki-2020-icon.svg', outreach = 'Wikimedia Outreach.png', incubator = 'Incubator-notext.svg', f = 'Wikifunctions-logo.svg', wm = 'Wikimedia-logo.svg' }
-- which logos are PD and don't need link/alt local PDicon = { m=true,q=true,d=true,outreach=true,wm=true }
-- which logos are dark and light and should flip in dark mode local darkOnLight = {wikt=true}
-- descriptive alt local logoAlt = { c = 'Wikimedia Commons logo', m = 'Meta-Wiki logo', b = 'Wikibooks logo', d = 'Wikidata logo', q = 'Wikiquote logo', iw = 'Wikipedia logo', s = 'Wikisource logo', wikt = 'Wiktionary logo', n = 'Wikinews logo', species = 'Wikispecies logo', v = 'Wikiversity logo', voy = 'Wikivoyage logo', mw = 'MediaWiki logo', outreach = 'Wikimedia Outreach logo', incubator = 'Wikimedia Incubator logo', f = 'Wikifunctions logo', wm = 'Wikimedia logo' }
-- size for [[Template:Wikipedia's sister projects]], defaults to 35px local largeSize = { c = '31px', d = '47px', n = '51px', v = '41px' }
return {projectMap=projectMap, logo=logo, PDicon=PDicon, darkOnLight=darkOnLight, logoAlt=logoAlt, largeSize=largeSize}

